# Core shape classes with virtual methods for inheritance
PI: float = 3.14159

class Shape:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return "Shape at (" + str(self.x) + ", " + str(self.y) + ")"

class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        super().__init__(0.0, 0.0)
        self.radius = radius

    @override
    def area(self) -> float:
        return PI * self.radius * self.radius

    @override
    def describe(self) -> str:
        return "Circle (r=" + str(self.radius) + ")"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__(0.0, 0.0)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return "Rectangle (" + str(self.width) + "x" + str(self.height) + ")"

