# Specialized shapes that inherit from base shapes
from shapes import Shape, Circle

class ColoredCircle(Circle):
    _color: str

    def __init__(self, radius: float, color: str):
        super().__init__(radius)
        self._color = color

    def get_color(self) -> str:
        return self._color

    @override
    def describe(self) -> str:
        return self._color + " " + super().describe()

class Drawing:
    shapes_list: list[Shape]

    def __init__(self):
        self.shapes_list = []

    def add_shape(self, shape: Shape) -> None:
        self.shapes_list.append(shape)

    def count_shapes(self) -> int:
        return len(self.shapes_list)

    def total_area(self) -> float:
        total = 0.0
        for shape in self.shapes_list:
            total += shape.area()
        return total

    def describe_all(self) -> None:
        for shape in self.shapes_list:
            print(shape.describe())
